create type cart_status as enum ('active','expired','abandoned','converted');
create type order_status as enum ('draft','pending','confirmed','preparing','ready','out_for_delivery','delivered','cancelled','rejected');
create table carts (id uuid primary key default gen_random_uuid(), tenant_id uuid not null, branch_id uuid not null, owner_type text not null check (owner_type in ('guest','customer')), owner_id uuid, status cart_status not null default 'active', version integer not null default 1, expires_at timestamptz not null, audit jsonb not null default '{}', created_at timestamptz not null default now(), updated_at timestamptz);
create table cart_items (id uuid primary key default gen_random_uuid(), tenant_id uuid not null, branch_id uuid not null, cart_id uuid not null references carts(id) on delete cascade, product_id uuid not null, menu_id uuid, combo_id uuid, quantity integer not null check (quantity > 0), notes text, modifiers jsonb not null default '[]', unit_price_preview jsonb, audit jsonb not null default '{}');
create table cart_sessions (id uuid primary key default gen_random_uuid(), tenant_id uuid not null, cart_id uuid not null references carts(id) on delete cascade, owner_type text not null check (owner_type in ('guest','customer')), owner_id uuid, anonymous_session_id text, expires_at timestamptz not null, audit jsonb not null default '{}');
create table order_drafts (id uuid primary key default gen_random_uuid(), tenant_id uuid not null, branch_id uuid not null, cart_id uuid not null, customer_id uuid, status text not null check (status in ('active','frozen','invalidated','expired')), totals jsonb not null default '{}', validation jsonb not null default '{}', pricing_context_id uuid, snapshot_frozen_at timestamptz, expires_at timestamptz not null, audit jsonb not null default '{}');
create table order_draft_items (id uuid primary key default gen_random_uuid(), tenant_id uuid not null, branch_id uuid not null, order_draft_id uuid not null references order_drafts(id) on delete cascade, cart_item_id uuid, product_id uuid not null, name_snapshot text not null, quantity integer not null check (quantity > 0), unit_price jsonb not null, modifiers_snapshot jsonb not null default '[]', line_total jsonb not null, audit jsonb not null default '{}');
create table orders (id uuid primary key default gen_random_uuid(), tenant_id uuid not null, branch_id uuid not null, draft_id uuid, status order_status not null default 'pending', customer jsonb not null default '{}', delivery jsonb not null default '{}', totals jsonb not null default '{}', audit jsonb not null default '{}', created_at timestamptz not null default now(), updated_at timestamptz);
create table order_items (id uuid primary key default gen_random_uuid(), tenant_id uuid not null, branch_id uuid not null, order_id uuid not null references orders(id) on delete cascade, product_id uuid not null, quantity integer not null check (quantity > 0), snapshot jsonb not null, line_total jsonb not null, audit jsonb not null default '{}');
create table order_snapshots (id uuid primary key default gen_random_uuid(), tenant_id uuid not null, branch_id uuid not null, order_id uuid not null references orders(id) on delete cascade, snapshot jsonb not null, frozen_at timestamptz not null default now(), audit jsonb not null default '{}');
create table order_timeline (id uuid primary key default gen_random_uuid(), tenant_id uuid not null, branch_id uuid not null, order_id uuid not null references orders(id) on delete cascade, status order_status not null, actor_id uuid, reason text, occurred_at timestamptz not null default now(), audit jsonb not null default '{}');
create table delivery_addresses (id uuid primary key default gen_random_uuid(), tenant_id uuid not null, customer_id uuid, line1 text not null, line2 text, city text not null, state text, postal_code text, country text not null default 'AR', coordinates jsonb, audit jsonb not null default '{}');
create table delivery_validations (id uuid primary key default gen_random_uuid(), tenant_id uuid not null, branch_id uuid not null, order_draft_id uuid, delivery_address_id uuid references delivery_addresses(id), valid boolean not null, reasons text[] not null default '{}', delivery_fee jsonb, estimated_delivery_minutes integer, distance_km numeric, audit jsonb not null default '{}');
alter table carts enable row level security; alter table cart_items enable row level security; alter table cart_sessions enable row level security; alter table order_drafts enable row level security; alter table order_draft_items enable row level security; alter table orders enable row level security; alter table order_items enable row level security; alter table order_snapshots enable row level security; alter table order_timeline enable row level security; alter table delivery_addresses enable row level security; alter table delivery_validations enable row level security;
